function ModelRank:OnRankResp(pb)
    --排行榜请求返回
    local type = pb.type
    local rankType = pb.rankType
    local page = pb.page
    local pageSize = pb.pageSize
    self._selfRank = self:GetStructRankInfo(pb.selfRank)
    local rankInfos = self._rankInfos
    if self._type ~= type or self._rankType ~= rankType or page == 1 then
        rankInfos = {}
    end
    for i, v in ipairs(pb.infos) do
        local rankInfo = self:GetStructRankInfo(v)
        if (type == 1) then
            rankInfos[rankInfo.type] = rankInfo
        else
            rankInfos[rankInfo.rank] = rankInfo
        end
    end
    self._rankInfos = rankInfos
    self._type = type
    self._rankType = rankType
    if ModelRank.RANK_MELEE == rankType then
        local ranks = {}
        for i, v in ipairs(pb.infos) do
            local rankInfo = self:GetStructRankInfo(v)
            table.insert(ranks, rankInfo)
        end
        table.sort(ranks, function(a, b)
            return a.rank < b.rank
        end)
        self._guildWarRank = ranks
    end
    FireEvent(EventNames.RANK_UPDATE_END, self._type, self._rankType)
end
