function ModelRank:OnMilestoneResp(pb)
    --里程碑信息请求返回
    local receiveIds = {}
    local infos = {}
    local rankType = pb.rankType
    for i, v in ipairs(pb.receiveIds) do
        receiveIds[v] = v
    end
    for i = 1, #pb.infos do
        local rankInfo = StructMileStoneInfo:New()
        rankInfo:CreateByPb(pb.infos[i])
        infos[pb.infos[i].refId] = rankInfo
    end
    self._milestone = { receiveIds = receiveIds, infos = infos }
end

