        local rankInfo = StructMileStoneInfo:New()
        rankInfo:CreateByPb(pb.infos[i])
        infos[i] = rankInfo
    end
    self._milestoneShowList = infos
end

function ModelRank:OnMileStoneReceiveResp(pb)
    --里程碑奖励返回
    local redB = false
    local receiveIds = pb.receiveId
    local rankType = pb.rankType
    if not self._milestone.receiveIds then
        return
    end
    for i, v in ipairs(receiveIds) do
        self._milestone.receiveIds[v] = v
    end
    for i, v in pairs(self._milestone.infos) do
        if (not self._milestone.receiveIds[i]) then
            redB = true
            break
        end
    end
    if (not redB) then
        gModelRedPoint:CheckRankRedClicked(rankType)
    end
end

function ModelRank:OnLikeHistoryResp(pb)

    if not self._likeIdList then
        self._likeIdList = {}
    end

    for k, v in ipairs(pb.infos) do
        local likeType = v.type
        local list = {}
        self._likeIdList[likeType] = list
        for k1, v1 in ipairs(v.playerIds) do
            if not list[v1] then
                list[v1] = 0
            end
            list[v1] = list[v1] + 1
        end
    end

    FireEvent(EventNames.ON_LIKE_HISTORY_RET)
end

