function ModelRank:OnGuildMeleeStateResp(pb)
    local state = pb.state or 0                     --联盟混战状态 （1.未开启状态（未开启当天无盟战），2.预备状态(未开启当天有盟战)
    local oldState = self._oldState or 0
    if (oldState < state) then
        if state == ModelGuildMelee.STATE_READY then
            self._guildWarRank = nil
        elseif state == ModelGuildMelee.STATE_APPLY then
            self._guildWarRank = nil
        end
    end
    self._oldState = state
end

