function ModelRank:CheckRankShow(randRefid)
    local checkShowList = {
        [ModelRank.RANK_ENDLES_COMPLEX] = ModelFunctionOpen.ENDLESS,
        [ModelRank.RANK_TOWER] = ModelFunctionOpen.RANK_TOWER,
        [ModelRank.RANK_ARENA_LEADER] = ModelFunctionOpen.RANK_AREA
    }
    local funId = checkShowList[randRefid]

    if randRefid == 201 then
        local servers = gModelGuildHolyBattle:GetServers()
        local count=servers  and  #servers  or  0
        
        return count > 1
    end

    if not funId then
        return true
    end
    return gModelFunctionOpen:CheckIsShow(funId)
end

function ModelRank:GetRankingRef(type, rankType, bool, isSmall)
    --获取排行榜小类型
    local list = {}
    if not bool then
        if (type ~= 1 or self._type ~= type or self._rankType ~= rankType) then
            return list
        end
    end
    local tRankType, sortSmall
    for i, v in pairs(GameTable.LeaderboardingRef) do
        tRankType = v.type
        sortSmall = v.sortSmall
        if (not isSmall and sortSmall == 0) or (isSmall and sortSmall ~= 0) then
            if tRankType == rankType and (isSmall or self:CheckRankShow(v.refId)) then
                table.insert(list, v)
            end
        end
    end
    table.sort(list, function(a, b)
        return a.sort < b.sort
    end)
    return list
end

