function ModelRank:GetMarkRef(refId)
    --获取里程碑数据
    local ref = self:GetRankingRefData(refId)
    local str = ccLngText(ref.text)
    local type = ref.markType
    local list = {}
    local milestone = self._milestone
    for i, v in pairs(GameTable.LeaderboardMarkRewardRef) do
        if (v.markType == type) then
            if milestone and milestone.receiveIds and milestone.infos then
                local data = { refId = v.refId }
                data.bReceive = milestone.receiveIds[v.refId] ~= nil
                data.infos = milestone.infos[v.refId]
                table.insert(list, data)
            end
        end
    end
    table.sort(list, function(a, b)
        --local aRe= a.bReceive and 0 or 1
        --local bRe = b.bReceive and 0 or 1
        --if aRe~= bRe then
        --    return  aRe>bRe
        --end

        return a.refId < b.refId
    end)
    return { str = str, list = list }
end

