function ModelRank:GetLikeRefTargetKey(likeType, keyStr)
    local likeRef = self:GetLikeRefByLikeType(likeType)
    if not likeRef then
        printInfoNR("GameTable.LikeHeartRef[likeType] is not find, likeType = " .. (likeType or "nil"))
        return nil
    end

    local resValue = likeRef[keyStr]
    if not resValue then
        printInfoNR("GameTable.LikeHeartRef[likeType]." .. keyStr .. " is not find, likeType = " .. (likeType or "nil"))
        return nil
    end

    return resValue
end

function ModelRank:IsLiked(likeType, playerId)
    if not self._likeIdList then
        return false
    end
    local list = self._likeIdList[likeType]
    if not list then
        return false
    end
    return list[playerId] ~= nil
end

function ModelRank:IsLikeLimit(likeType, showTip)
    if not self._likeIdList then
        return false
    end
    local list = self._likeIdList[likeType]

    local cnt = 0
    if list then
        for k, v in pairs(list) do
            if type(v) == "boolean" then
                cnt = cnt + 1
            elseif type(v) == "number" then
                cnt = cnt + v
            end
        end
    end

    local cfg = GameTable.LikeHeartRef[likeType]
    if not cfg then
        return false
    end
    local maxTime = cfg.time
    if cnt < maxTime then
        return false
    end
    if showTip then
        GF.ShowMessage(string.replace(ccClientText(11879), maxTime))
    end
    return true
end

function ModelRank:IsLikeTimeRewardLimit(likeType)
    if not self._likeIdList then
        return false
    end
    local list = self._likeIdList[likeType]

    local cnt = 0
    if list then
        for k, v in pairs(list) do
            if type(v) == "boolean" then
                cnt = cnt + 1
            elseif type(v) == "number" then
                cnt = cnt + v
            end
        end
    end

    local cfg = GameTable.LikeHeartRef[likeType]
    if not cfg then
        return false
    end
    local maxTime = cfg.timeReward
    if cnt < maxTime then
        return false
    end
    return true
end



--[[ rewarddata =
{
    refId,
    type,
    rankMin,
    rankMax,
    reward,
}
]]

function ModelRank:GemRankRewardList(tableName)
    local rankAwardRef = GameTable[tableName]
    local rewardList = {}
    for i, v in pairs(rankAwardRef) do
        local rewardData = {
            refId = v.refId,
            type = v.type,
        }

        local strs = string.split(v.rank, ',')
        rewardData.rankMax = tonumber(strs[1])
        rewardData.rankMin = tonumber(strs[2])
        rewardData.reward = LxDataHelper.ParseItem(v.reward)
        table.insert(rewardList, rewardData)
    end
    table.sort(rewardList, function(a, b)
        if a.sort and b.sort then
            return a.sort < b.sort
        else
            return a.refId < b.refId
        end
    end)

    return rewardList
end

