end

function ModelRank:CheckIsDayEndRank(rankRefId)
    local rankDayEndList = ModelRank:GetRankingConfigRefByKey("rankDayEndList")
    if (rankDayEndList) then
        local list = string.split(rankDayEndList, ",")
        for i, v in pairs(list) do
            if (tonumber(v) == rankRefId) then
                return true
            end
        end
    end
end

